module edge_detect (
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);

    reg a_delayed;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            a_delayed <= 1'b0;
            rise <= 1'b0;
            down <= 1'b0;
        end else begin
            a_delayed <= a;
            rise <= (a == 1'b1 && a_delayed == 1'b0) ? 1'b1 : 1'b0;
            down <= (a == 1'b0 && a_delayed == 1'b1) ? 1'b1 : 1'b0;
        end
    end

endmodule
